#include<bits/stdc++.h>
using namespace std;
long long a[100010],f[100010];
int main()
{
    long long n,t;
    scanf("%lld%lld",&n,&t);
    for(long long i=1;i<=n;i++)
    {
        long long p,v;
        scanf("%lld%lld",&p,&v);
        a[i]=p+v*t;
    }
    f[0]=2e18;
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        if(a[i]<=f[ans])
        {
            f[++ans]=a[i];
        }
        else
        {
            f[upper_bound(f+1,f+1+ans,a[i],greater<long long>())-f]=a[i];
        }
    }
    printf("%lld",ans);
    return 0;
}
